def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 7
        for step in range(steps):
            if ratio > 1:
                score += 50 * decay
                break
            if ratio < 0.0001:
                score += 0.1 * decay
                break
            part1 = (np.exp(-ratio * (step + 1)) + np.tanh(ratio * 10 * (step + 1))) * decay
            part2 = (np.log1p(ratio * 100) / (step + 2)) * decay
            part3 = (np.sin(ratio * np.pi * (step + 0.5))) ** 2 * decay
            score += part1 + part2 + part3
            if ratio < 0.3:
                score += (5 - step) * 0.3 * decay
            elif 0.6 < ratio < 0.9:
                score -= step * 0.5 * decay
            else:
                score += 0.2 * step * decay
            decay *= 0.75
            if score > 15:
                break
        if ratio < 0.5:
            for k in range(3):
                score += ((0.5 / (k + 1)) * (1 - ratio)) ** 2
        elif ratio > 0.7:
            for k in range(2):
                if capacity < item * (1 + 0.1 * k):
                    score += 3 * (k + 1)
        if capacity < item * 0.95:
            score += 25
        if capacity > item * 2:
            score /= 2
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 200
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 1.7
            else:
                priorities[i] = (priorities[i] - p_min) / (p_max - p_min) * 20
    return priorities
